INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm0',
  '0-1',
  'Define Your ICP Using the Caroline Framework',
  $body$:::info Build Context
:::

## Steps

1. Pick one real past client who was your favorite to work with. This is your "Caroline." Not an archetype — an actual person with a name.

2. Document their personal traits: How do they communicate? Are they direct or cautious? Do they use Slack or email? What frustrates them about their job specifically?

3. Document their business context: Industry vertical, company size, growth stage, business model, team structure.

4. Write down their top 3 problems IN THEIR LANGUAGE — not your service language. If they say "I can't get leads" don't write "inefficient demand generation."

5. Define personality traits that make them ideal: responsive, decisive, values expertise, has budget authority.

6. Define your anti-ICP: the traits of clients you do NOT want. Document these just as specifically.

7. Run the Gobbledygook Test: show your homepage or LinkedIn headline to someone outside your industry. If they understand it, your messaging is too generic. Your ICP should self-select; non-ICP should be confused.

8. Write a single sentence: "I want more [Caroline's name]s." This is your targeting north star for every tool you configure.$body$,
  '[{"check":"ICP is based on a real past client, not an archetype or composite persona","severity":"critical"},{"check":"Client problems documented in their own language, not service provider jargon","severity":"critical"},{"check":"Anti-ICP traits are defined as specifically as ideal ICP traits","severity":"warning"},{"check":"Gobbledygook Test passed: messaging is industry-specific enough that non-ICP prospects are confused","severity":"warning"},{"check":"Single targeting north star sentence created and documented","severity":"info"}]'::jsonb,
  '[{"type":"icp_definition","description":"A detailed ICP profile based on the Caroline Framework including personal traits, business context, top 3 problems in client language, ideal personality traits, anti-ICP definition, and a single targeting north star sentence"}]'::jsonb,
  ARRAY[]::text[],
  ARRAY[]::text[],
  1
)
