INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm0',
  '0-2',
  'Magnet Lab ICP Intake',
  $body$:::info Build Context
:::

## Steps

1. Open Magnet Lab and navigate to the ICP Intake tool.
2. Answer each question the tool asks about your ideal client — pull directly from your Caroline Framework notes.
3. Provide as much context as possible: paste in client call transcripts, website copy, testimonials, past proposals.
4. The tool will use this context to configure all downstream Magnet Lab tools (Ideator, Creator, Post Writer, etc.).
5. Review the output. Edit anything that doesn't sound like you or doesn't match your Caroline.
6. Save. This becomes the foundation for every lead magnet, post, and email the system generates.$body$,
  '[{"check":"ICP definition must directly reference Caroline Framework notes and include specific client context (call transcripts, website copy, or testimonials)","severity":"critical"},{"check":"Output tone and positioning must match the user''s voice and existing Caroline Framework — review and edit before saving","severity":"critical"},{"check":"All downstream Magnet Lab tools (Ideator, Creator, Post Writer) are configured from this intake — incomplete or inaccurate input cascades downstream","severity":"warning"},{"check":"Provide maximum context possible (transcripts, copy, testimonials) rather than minimal answers to improve tool accuracy","severity":"info"}]'::jsonb,
  '[{"type":"icp_definition","description":"Configured Ideal Client Profile saved in Magnet Lab that serves as the foundation for all downstream content, lead magnets, emails, and posts"}]'::jsonb,
  ARRAY['magnetlab_ideator', 'magnetlab_creator', 'magnetlab_post_writer']::text[],
  ARRAY[]::text[],
  1
)
