INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm2',
  '2-6',
  'Detect LinkedIn Activity and Segment Your TAM',
  $body$:::info Build Context
:::

## Steps

1. In Clay, add an enrichment column to detect LinkedIn activity (whether the contact has posted in the last 30 days).
2. Run the enrichment on your full TAM.
3. Segment your TAM into groups based on the results:
4. **Segment A:** Active on LinkedIn + has email → DM outreach via HeyReach + cold email via PlusVibe + LinkedIn ads.
5. **Segment B:** Active on LinkedIn + no email → DM outreach only via HeyReach + LinkedIn ads (company list).
6. **Segment C:** Not active on LinkedIn + has email → Cold email only via PlusVibe.
7. **Segment D:** Not active + no email → Deprioritize or find through other channels.
8. Export each segment as a separate CSV for its respective outreach channel.$body$,
  '[{"check":"All contacts in TAM have been enriched with LinkedIn activity status (posted in last 30 days: yes/no)","severity":"critical"},{"check":"TAM is cleanly segmented into exactly 4 groups (A, B, C, D) based on LinkedIn activity + email availability","severity":"critical"},{"check":"Each segment has been exported as a separate CSV file ready for its designated outreach channel","severity":"critical"},{"check":"Segment routing aligns with available contact data (no cold email attempted for contacts without email addresses)","severity":"warning"}]'::jsonb,
  '[{"type":"tam_segment","description":"Four segmented CSV files (Segment A, B, C, D) of TAM contacts grouped by LinkedIn activity status and email availability for targeted outreach"}]'::jsonb,
  ARRAY['clay', 'heyreach', 'plusvibe', 'linkedin_ads_manager']::text[],
  ARRAY['2-5']::text[],
  1
)
