INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm3',
  '3-1',
  'Set Up a HeyReach Connection Campaign',
  $body$:::info Build Context
:::

## Steps

1. Log into HeyReach.
2. Create a new campaign.
3. Import your Segment A or B list (LinkedIn-active contacts).
4. Configure the sequence: Step 1 — Send connection request (BLANK — no note). Step 2 — If accepted, send first message. Step 3 — If already connected, like their most recent post.
5. Write your first message template. Options: (a) "Hey [first_name], how's business?" (b) "Hey [first_name], great to connect. I help [niche] get [outcome]. How's your year going so far?" (c) Custom opener matching your style.
6. Add a fallback message without the first name variable in case data is missing.
7. Set daily send limits within HeyReach's recommended range.
8. Launch the campaign.$body$,
  '[{"check":"Connection request sent without a note as first step to avoid spam filters","severity":"critical"},{"check":"First message template includes personalization ([first_name]) with a fallback message for missing data","severity":"critical"},{"check":"Daily send limits configured within HeyReach''s recommended range to maintain deliverability","severity":"warning"},{"check":"Imported list contains only LinkedIn-active contacts from Segment A or B","severity":"warning"}]'::jsonb,
  '[{"type":"outreach_campaign","description":"Configured HeyReach connection campaign with message sequences and daily send limits"}]'::jsonb,
  ARRAY['heyreach']::text[],
  ARRAY[]::text[],
  1
)
