INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm3',
  '3-2',
  'Message Matching — Write a Personalized Second DM',
  $body$:::info Build Context
:::

## Steps

1. When someone replies to your first message, STOP the automation. The second message is always manual.
2. Spend 3–4 minutes researching their profile: read their headline, About section, recent posts, and comments.
3. Note their communication style: Are they formal or casual? Do they use emojis or corporate language? Long-form or terse?
4. Match their style in your response. If they write short casual messages, you write short casual messages. If they write professional paragraphs, match that.
5. Reference something specific from their profile or posts. Show you actually looked.
6. Keep the conversation going naturally — do NOT pivot to a pitch yet. Build the relationship first.
7. When the timing is right (they ask what you do, or express a relevant pain point), offer your lead magnet or suggest a call.$body$,
  '[{"check":"Second DM must reference a specific detail from prospect''s profile, posts, or recent activity","severity":"critical"},{"check":"Communication style must match prospect''s tone (formal/casual, emoji use, message length)","severity":"critical"},{"check":"No pitch or lead magnet mention until prospect expresses interest or pain point","severity":"warning"},{"check":"Research phase completed in 3–4 minutes before composing response","severity":"info"}]'::jsonb,
  '[{"type":"dm_campaign","description":"Personalized second direct message with style-matched tone and profile-specific reference"}]'::jsonb,
  ARRAY['linkedin']::text[],
  ARRAY['3-1']::text[],
  1
)
