INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm4',
  '4-1',
  'Provision Cold Email Domains with ZapMail',
  $body$:::info Build Context
:::

## Steps

1. Go to ZapMail and select your plan (starter or growth depending on scale).
2. ZapMail will automatically set up: domain purchase, DKIM, SPF, DMARC records, and USMTP integration.
3. For DWY builds: provision 10 domains with 2 email accounts each (20 accounts total).
4. For Tim's scale: 104 domains with 275 email accounts.
5. Each account sends a maximum of 25–30 emails per day to stay under spam thresholds.
6. If targeting enterprise clients, purchase aged domains (6+ months old). Enterprise email filters flag new domains.
7. Once domains are provisioned, connect the mailboxes to PlusVibe.$body$,
  '[{"check":"All DNS records (DKIM, SPF, DMARC) are properly configured by ZapMail before sending","severity":"critical"},{"check":"Email sending volume does not exceed 25-30 emails per account per day","severity":"critical"},{"check":"Enterprise targeting uses aged domains (6+ months old) to avoid spam filters","severity":"warning"},{"check":"All provisioned mailboxes are successfully connected to PlusVibe","severity":"warning"}]'::jsonb,
