INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm4',
  '4-2',
  'Warm Up Email Accounts in PlusVibe',
  $body$:::info Build Context
:::

## Steps

1. In PlusVibe, your ZapMail accounts should already be connected.
2. Go to Edit Settings → Warmup Settings.
3. Leave the default warmup configuration — PlusVibe's automation is excellent.
4. The warmup schedule: start at 5 emails/day, increase by 2 emails every 2 days, until reaching 25–30 emails/day.
5. Let accounts warm for a minimum of 2 weeks (ideally 3 weeks) before sending any cold campaign emails.
6. Choose Google Workspace accounts if targeting startups. Choose Microsoft 365 if targeting enterprise.
7. Do not send any campaign emails until warmup is complete.

:::warning Critical Timing
Email warmup starts on Day 1 of the build. The 21-day warmup period means cold email auto-fires around Day 21 — approximately 10 days after the build engagement ends. This is the only hard constraint that can't be compressed.
:::$body$,
  '[{"check":"Warmup period is minimum 2 weeks, ideally 3 weeks before any cold campaign emails are sent","severity":"critical"},{"check":"No campaign emails sent during warmup phase — warmup-only emails must complete first","severity":"critical"},{"check":"Email volume follows schedule: 5 emails/day starting point, increasing by 2 emails every 2 days up to 25-30 emails/day","severity":"warning"},{"check":"Correct email provider selected based on target audience (Google Workspace for startups, Microsoft 365 for enterprise)","severity":"warning"},{"check":"ZapMail accounts are connected before beginning warmup configuration","severity":"info"}]'::jsonb,
  '[{"type":"email_infrastructure","description":"Warmed and authenticated email accounts in PlusVibe ready for cold campaign deployment"}]'::jsonb,
  ARRAY['plusvibe', 'zapmail']::text[],
  ARRAY['4-1']::text[],
  1
)
