INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm4',
  '4-4',
  'Launch a Cold Email Campaign in PlusVibe',
  $body$:::info Build Context
:::

## Steps

1. Import your validated email list (Segment C from Module 2, or full TAM with emails).
2. Create a new campaign in PlusVibe.
3. Add your email copy with variable fields mapped to your data columns.
4. Set sending volume: 25–30 emails per day per account.
5. Set sending schedule: business hours in your prospect's timezone.
6. Add follow-up emails (2–3 follow-ups spaced 3–5 days apart if no reply).
7. Launch the campaign.
8. Monitor daily: check open rates, reply rates, bounce rates, and spam complaints.
9. If bounce rate exceeds 3%, pause and revalidate your list. If spam complaints rise, review copy and reduce volume.$body$,
  '[{"check":"Bounce rate must not exceed 3%; pause and revalidate list if threshold breached","severity":"critical"},{"check":"Email list must be validated before import (from Module 2 Segment C or full TAM with verified emails)","severity":"critical"},{"check":"All variable fields in email copy must be correctly mapped to data columns to prevent blank or incorrect personalization","severity":"critical"},{"check":"Sending volume capped at 25–30 emails per day per account to maintain deliverability","severity":"warning"},{"check":"If spam complaints rise, review email copy and reduce sending volume immediately","severity":"warning"},{"check":"Follow-up sequence should include 2–3 emails spaced 3–5 days apart for non-responders","severity":"info"}]'::jsonb,
  '[{"type":"email_campaign","description":"Configured and launched cold email campaign with validated prospect list, personalized copy, sending schedule, and follow-up sequence in PlusVibe"}]'::jsonb,
  ARRAY['plusvibe']::text[],
  ARRAY['2-3']::text[],
  1
)
