INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm5',
  '5-5',
  'Rotate Ad Content to Prevent Fatigue',
  $body$:::info Build Context
:::

## Steps

1. Monitor ad performance weekly. Key signals: engagement rate dropping, same commenters appearing, fewer DMs from new ICPs.
2. When a post shows fatigue (typically after 3–6 months on LinkedIn due to high CPMs), turn it off.
3. Rotate in a different post from your reserve set.
4. Rotation system: maintain 6 total posts. Run 3 at a time. When those fatigue, swap in the other 3. When those fatigue, swap back to the first 3 — people forget they saw them.
5. Continuously create new lead magnets and case study posts to expand your rotation pool.
6. Never delete fatigued posts — just pause them. They'll perform again after a rest period.$body$,
  '[{"check":"Monitor ad performance weekly and identify fatigue signals (dropping engagement rate, repeat commenters, fewer new ICP DMs)","severity":"critical"},{"check":"Maintain minimum 6 posts in rotation pool with at least 3 active at any time","severity":"critical"},{"check":"Pause fatigued posts rather than deleting them to enable future re-use","severity":"warning"},{"check":"Continuously create new lead magnets and case study posts to expand rotation pool and prevent creative staleness","severity":"warning"}]'::jsonb,
  '[{"type":"ad_campaign","description":"Rotated ad campaign with refreshed creatives swapped on weekly/monthly cadence to combat audience fatigue"}]'::jsonb,
  ARRAY['linkedin_ads_manager', 'linkedin']::text[],
  ARRAY['5-3', '5-4']::text[],
  1
)
