INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm6',
  '6-1',
  'Daily Operating Rhythm',
  $body$:::info Build Context
:::

## Steps

1. Block 60–90 minutes in your calendar for system operations. Same time every day.
2. **15 min — Check DMs:** review new conversations. Respond to warm leads personally. Flag high-value prospects for deeper follow-up (SOP 3.4).
3. **15 min — Post content:** publish your daily post. Engage with 3–5 comments on other people's content in your niche.
4. **10 min — Monitor automations:** check Leadshark for new lead magnet comments. Check HeyReach for new connections. Check email sequences for replies.
5. **10 min — Review metrics:** glance at email open rates, DM response rates, ad spend. Note anything unusual.
6. **10 min — Trend scan:** scroll your feed for 5–10 minutes. Note what's resonating. Collect lead magnet ideas.$body$,
  '[{"check":"Daily operating rhythm scheduled at the same time every day with 60–90 minutes blocked","severity":"critical"},{"check":"All six daily blocks (DMs, content, automations, metrics, trends) completed within the time window","severity":"critical"},{"check":"Warm leads responded to personally and high-value prospects flagged for follow-up","severity":"warning"},{"check":"3–5 comments engaged with on other people''s content daily","severity":"info"},{"check":"Metrics reviewed for anomalies (open rates, DM response rates, ad spend)","severity":"warning"}]'::jsonb,
