INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm6',
  '6-2',
  'Weekly System Review (30 Minutes)',
  $body$:::info Build Context
:::

## Steps

1. Pick one day per week (Friday recommended). Block 30 minutes.
2. Review lead magnet performance: which magnets are generating the most opt-ins? Which are getting the most comments? Time to refresh any?
3. Review DM pipeline: how many active conversations? How many moved toward a call? Where are conversations stalling?
4. Review cold email metrics: open rates, reply rates, bounce rates. Are domains staying warm? Any campaigns underperforming?
5. Review ad performance: cost per engagement trending up or down? Which posts are fatiguing? Time to rotate?
6. Review call bookings: how many qualified calls booked this week? Which channel sourced them?
7. Make one decision: what's the single highest-leverage thing to change or add next week?$body$,
  '[{"check":"Weekly review completed every Friday with all 6 metrics reviewed (lead magnets, DM pipeline, cold email, ads, call bookings, channel attribution)","severity":"critical"},{"check":"One high-leverage decision documented and actioned for the following week","severity":"critical"},{"check":"30-minute time block strictly adhered to—avoid analysis paralysis","severity":"warning"},{"check":"Review focuses on trend identification (up/down/stalling) rather than perfectionism on individual metrics","severity":"info"}]'::jsonb,
