INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm6',
  '6-3',
  'Scale from Solo Operator to Setter + VA',
  $body$:::info Build Context
:::

## Steps

1. **Trigger:** you're getting consistent 20–30% response rates on first messages, your pipeline is growing, but you can't personally respond to everyone.
2. Hire a setter (part-time or contractor). Their job: send connection requests (blank), send the first templated message, monitor responses, qualify prospects, and hand off warm leads to you.
3. The first message stays templated ("How's business?"). The setter never writes manual second messages — that's your job.
4. Give the setter access to HeyReach and train them on your qualification criteria (who's an ICP match, who isn't).
5. Optionally hire a VA for list management: exporting data, running Clay enrichments, uploading lists, monitoring email deliverability.
6. Your role shifts to: content creation, manual follow-ups on qualified leads, closing calls, and strategy.$body$,
  '[{"check":"Setter sends only templated first messages; no custom second messages written by setter","severity":"critical"},{"check":"Setter is trained on ICP qualification criteria before being given HeyReach access","severity":"critical"},{"check":"Founder maintains 20-30% first message response rate as baseline before delegating","severity":"warning"},{"check":"VA handles all list management, enrichment, and deliverability monitoring tasks","severity":"info"}]'::jsonb,
  '[{"type":"operating_playbook","description":"Setter and VA role definitions, responsibilities, and qualification training framework"}]'::jsonb,
  ARRAY['heyreach']::text[],
  ARRAY['6-1', '6-2']::text[],
  1
)
