INSERT INTO program_sops (module_id, sop_number, title, content, quality_bars, deliverables, tools_used, dependencies, version)
VALUES (
  'm7',
  '7-1',
  'Load Transcripts into Magnet Lab',
  $body$:::info Build Context
:::

## Steps

1. Gather 3–5 transcripts: client calls, podcast episodes, workshop recordings, or coaching sessions where you talked about your expertise.
2. Open Magnet Lab's Content Engine.
3. Upload or paste each transcript.
4. Magnet Lab ingests the transcripts and extracts insights, stories, frameworks, and opinions from your natural speech.
5. Review the auto-generated content idea queue. Each idea will be tagged with a content pillar (Authority, Relatability, Proof, or Value) and a suggested format.
6. Kill the weak ideas. Star the ones that excite you. Edit any that need a different angle.
7. Your goal: maintain a queue of at least 14 ideas ahead at all times (2 weeks of content).$body$,
  '[{"check":"Maintain a minimum of 14 content ideas in the queue at all times (2 weeks ahead)","severity":"critical"},{"check":"All uploaded transcripts must be from authentic expertise contexts (client calls, podcasts, workshops, coaching sessions)","severity":"critical"},{"check":"Content ideas must be properly tagged with a content pillar (Authority, Relatability, Proof, or Value)","severity":"warning"},{"check":"Review and curate ideas by starring high-potential ones and removing weak ideas to maintain queue quality","severity":"warning"}]'::jsonb,
  '[{"type":"content_plan","description":"Queue of at least 14 curated content ideas extracted from transcripts, tagged by pillar and format, with starred high-potential ideas ready for creation"}]'::jsonb,
  ARRAY['magnetlab_content_pipeline']::text[],
  ARRAY[]::text[],
  1
)
